// LinkedIn API-Antworten aufbereiten + filtern (Entscheider + IT-Thema oder >50 Reaktionen)
const items = $input.all();
const result = [];
const seenTexts = new Set();

const ENTSCHEIDER = ['vorstand','ceo','cio','cto','cdo','coo','cfo','geschäftsführer','vorsitzender','geschäftsbereichsleiter','leiter geschäftsbereich','bereichsleiter','head of','it-leiter','digitalisierungsleiter'];
const THEMEN_IT = ['ki ','künstliche intelligenz','automatisierung','digitalisierung','software','cloud','plattform',' api ','daten','system','it-','cyber','sicherheit','technologie','agil','scrum'];

for (const item of items) {
  const posts = item.json.data || item.json.posts || item.json.elements || [];
  for (const post of Array.isArray(posts) ? posts : []) {
    const text = (post.text || post.commentary || post.content || '').trim();
    if (!text || text.length < 20) continue;
    const textKey = text.substring(0, 80);
    if (seenTexts.has(textKey)) continue;
    seenTexts.add(textKey);

    const author = post.author || {};
    const actorName = author.fullName || author.name || post.authorName || '';
    const actorTitle = (author.headline || author.title || '').toLowerCase();
    const likes = parseInt(post.totalReactionCount || post.numLikes || post.likes || 0);
    const comments = parseInt(post.numComments || post.comments || 0);
    const reactions = likes + comments;

    const isEntscheider = ENTSCHEIDER.some(k => actorTitle.includes(k));
    const isItThema = THEMEN_IT.some(k => text.toLowerCase().includes(k));
    const isViral = reactions >= 50;

    // Nur Entscheider-Posts; davon nur IT-Themen oder virale Posts
    if (!isEntscheider && !isViral) continue;
    if (isEntscheider && !isItThema && !isViral) continue;

    result.push({ json: {
      _source: 'LinkedIn',
      title: text.substring(0, 120),
      text: text,
      link: post.url || post.postUrl || post.shareUrl || '',
      postedAt: post.postedAt || post.date || '',
      author: actorName,
      contentSnippet: `${actorName}${actorTitle ? ' (' + actorTitle.substring(0,60) + ')' : ''}: ${text.substring(0,300)} (👍${likes} 💬${comments})`
    }});
  }
}
return result;

// Deduplizierung: Items mit bereits gesehenen URLs/Hashes überspringen
const items = $input.all();
const seen = new Set();
const fresh = [];

for (const item of items) {
  const key = item.json.url || item.json.link || item.json.id || 
              (item.json.text || '').substring(0, 80);
  const hash = key.replace(/\s+/g, '').toLowerCase();
  if (!seen.has(hash)) {
    seen.add(hash);
    fresh.push({ ...item, json: { ...item.json, _hash: hash } });
  }
}

// Nur Items der letzten 2 Tage (täglicher Newsletter)
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 2);

return fresh.filter(item => {
  const pub = item.json.pubDate || item.json.postedAt || item.json['publication-date'];
  if (!pub) return true;
  return new Date(pub) >= cutoff;
});

// Rohdaten für Claude zusammenstellen
const items = $input.all();
let text = '## Rohdaten dieser Ausgabe\n\n';

for (const item of items) {
  const src = item.json._source || 'Unbekannt';
  const title = item.json.title || item.json.text?.substring(0, 100) || 'Kein Titel';
  const url = item.json.url || item.json.link || '';
  const date = item.json.pubDate || item.json.postedAt || '';
  const body = item.json.contentSnippet || item.json.text?.substring(0, 400) || '';

  text += `### [${src}] ${title}\n`;
  if (date) text += `Datum: ${date}\n`;
  if (url) text += `URL: ${url}\n`;
  if (body) text += `${body}\n`;
  text += '\n';
}

return [{ json: { rohdaten: text, item_count: items.length } }];

const haiku = $input.first().json;
const scored = haiku.content?.[0]?.text || '';
return [{ json: { haiku_scored: scored } }];

// Newsletter-Text aus Claude-Response extrahieren
const response = $input.first().json;
const text = response.content?.[0]?.text || 'Fehler: Kein Newsletter generiert';

// Einfache Markdown→HTML Konvertierung für Email
const html = `<!DOCTYPE html>
<html lang="de">
<head><meta charset="utf-8"><style>
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Arial, sans-serif; background: #f1f5f9; margin: 0; padding: 24px 8px 48px; color: #1e293b; font-size: 15px; line-height: 1.7; }
.wrapper { max-width: 640px; margin: 0 auto; }
.header { background: #0f172a; padding: 32px 36px 28px; text-align: center; border-radius: 14px 14px 0 0; }
.header-eyebrow { font-size: 11px; font-weight: 700; letter-spacing: 3px; text-transform: uppercase; color: #38bdf8; margin: 0 0 10px; }
.header h1 { font-size: 28px; font-weight: 800; color: #f8fafc; margin: 0 0 8px; }
.header-sub { font-size: 13px; color: #64748b; margin: 0 0 20px; }
.header-meta { font-size: 12px; color: #475569; border-top: 1px solid #1e293b; padding-top: 14px; }
.header-meta span { color: #38bdf8; font-weight: 600; }
.card { background: #fff; padding: 36px; border-radius: 0 0 14px 14px; border: 1px solid #e2e8f0; border-top: none; }
h2 { font-size: 17px; font-weight: 700; color: #0f172a; margin: 40px 0 12px; padding: 13px 16px; background: #f8fafc; border-left: 4px solid #38bdf8; border-radius: 0 8px 8px 0; }
h2:first-child { margin-top: 0; }
h3 { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.4px; color: #94a3b8; margin: 22px 0 6px; }
ul { list-style: none; padding: 0; margin: 4px 0 14px; }
li { padding: 8px 12px 8px 14px; border-left: 3px solid #38bdf8; border-radius: 0 5px 5px 0; margin-bottom: 3px; color: #334155; background: #f8fafc; font-size: 14px; }
li:nth-child(even) { border-left-color: #cbd5e1; background: #fff; }
p { margin: 8px 0; color: #334155; }
blockquote { margin: 14px 0; padding: 13px 18px; background: #fefce8; border-left: 4px solid #eab308; border-radius: 0 8px 8px 0; color: #713f12; font-size: 14px; }
strong { color: #0f172a; font-weight: 600; }
a { color: #2563eb; text-decoration: none; font-weight: 500; }
.footer { text-align: center; margin-top: 20px; color: #94a3b8; font-size: 12px; line-height: 2; }
</style></head>
<body><div class="wrapper">
<div class="header">
  <p class="header-eyebrow">Wöchentlicher Branchenbrief</p>
  <h1>KassenInfodienst</h1>
  <p class="header-sub">Nur was zählt — kuratiert, analysiert, direkt.</p>
  <p class="header-meta">GKV Marktintelligenz &bull; <span>${new Date().toLocaleDateString('de-DE', {day:'2-digit',month:'long',year:'numeric'})}</span></p>
</div>
<div class="card">
${text
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^> (.+)$/gm, '<blockquote>$1</blockquote>')
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\n{2,}/g, '</p><p>')
  .replace(/^([^<\n].+)$/gm, '<p>$1</p>')
  .replace(/<p><\/p>/g, '')
}
</div>
<div class="footer">Erstellt mit Claude Sonnet 4.6 via n8n &bull; ${new Date().toLocaleDateString('de-DE', {day:'2-digit',month:'long',year:'numeric'})}</div>
</div></body></html>`;

return [{ json: { newsletter_text: text, newsletter_html: html, generated_at: new Date().toISOString() } }];
